arguments.file_text:
const storageKey = "notepad-content";

export function load() {
    return localStorage.getItem(storageKey) || "";
}

export function save(content) {
    localStorage.setItem(storageKey, content);
}

export function clear() {
    localStorage.removeItem(storageKey);
}

let beforeUnloadHandler = null;

export function enableUnloadPrompt() {
    if (!beforeUnloadHandler) {
        beforeUnloadHandler = (e) => {
            e.preventDefault();
        };
        window.addEventListener("beforeunload", beforeUnloadHandler);
    }
}

export function disableUnloadPrompt() {
    if (beforeUnloadHandler) {
        window.removeEventListener("beforeunload", beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="content" @bind:event="oninput"></textarea>
</div>

<div class="d-flex align-items-center gap-3 mb-3">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = "";
    private string savedContent = "";
    private DateTime? lastSavedAt;
    private IJSObjectReference? module;
    private System.Threading.Timer? autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Notepad.razor.js");

            var loaded = await module.InvokeAsync<string>("load");
            if (!string.IsNullOrEmpty(loaded))
            {
                content = loaded;
                savedContent = loaded;
                StateHasChanged();
            }

            autoSaveTimer = new System.Threading.Timer(
                async _ => await InvokeAsync(AutoSave), null,
                TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    private bool HasUnsavedChanges => content != savedContent;

    private async Task AutoSave()
    {
        if (HasUnsavedChanges)
        {
            await Save();
            StateHasChanged();
        }
    }

    private async Task SaveNow()
    {
        await Save();
    }

    private async Task Save()
    {
        if (module is null) return;
        await module.InvokeVoidAsync("save", content);
        savedContent = content;
        lastSavedAt = DateTime.Now;
        await module.InvokeVoidAsync("disableUnloadPrompt");
    }

    private async Task Clear()
    {
        if (module is null) return;
        content = "";
        savedContent = "";
        lastSavedAt = null;
        await module.InvokeVoidAsync("clear");
        await module.InvokeVoidAsync("disableUnloadPrompt");
    }

    protected override async Task OnAfterRenderAsync_UpdateUnload()
    {
        // This method doesn't exist; see the real update below.
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
        {
            await autoSaveTimer.DisposeAsync();
        }
        if (module is not null)
        {
            await module.InvokeVoidAsync("disableUnloadPrompt");
            await module.DisposeAsync();
        }
    }
}

